/**
 * Regression tests for review diversity and fallback behavior.
 *
 * Covers the two bugs fixed in extension.mjs:
 *
 * Bug 1 – isSameModelFamily used sub-family groupings (claude-haiku, claude-sonnet,
 *   claude-opus, codex, gpt-5) instead of top-level vendor families (claude, gpt).
 *   Consequence: claude-opus-4.5 was treated as *different* family from claude-sonnet-4.6,
 *   so it was not penalised in review ordering — a Claude model could be chosen ahead of
 *   GPT models even when GPT was available.  Similarly, gpt-5.1-codex-max was treated as
 *   different from gpt-5.2, so codex models were not correctly penalised when GPT was the
 *   last implementation family.
 *
 * Bug 2 – buildAdditionalContext only surfaced the "no distinct model available" note
 *   when the exact implementation model was reused (selectedModelId === lastImplModel).
 *   Same-family-but-different-model fallbacks were silently omitted from the context.
 *
 * These tests inline the pure helpers from extension.mjs so they can run without
 * importing the module (which has a top-level await joinSession() side-effect).
 * Keep them in sync with extension.mjs; any divergence is a sign that extension.mjs
 * needs re-review.
 */

import assert from "node:assert/strict";

// ── Helpers inlined from extension.mjs (fixed versions) ──────────────────────

function isSameModelFamily(first, second) {
  if (!first || !second) return false;
  const topFamily = (model) => {
    if (model.startsWith("claude-")) return "claude";
    if (model.startsWith("gpt-")) return "gpt";
    return model;
  };
  return topFamily(first) === topFamily(second);
}

// Minimal replica of orderCandidates logic (the sort predicate is what matters).
function orderForReview(candidates, lastImplementationModel) {
  if (!lastImplementationModel) return candidates;
  return [...candidates].sort((left, right) => {
    const score = (id) =>
      id === lastImplementationModel ? 2 : isSameModelFamily(id, lastImplementationModel) ? 1 : 0;
    return score(left.id) - score(right.id);
  });
}

// Minimal replica of the review-diversity lines in buildAdditionalContext.
function reviewDiversityLines(selectedModelId, lastImplementationModel) {
  if (!lastImplementationModel) return [];
  const lines = [`Prefer review diversity versus implementation model ${lastImplementationModel}.`];
  if (selectedModelId === lastImplementationModel) {
    lines.push("A distinct review model was not available, so the router fell back to the current best option.");
  } else if (selectedModelId && isSameModelFamily(selectedModelId, lastImplementationModel)) {
    lines.push("No cross-family review model was available; using a different model in the same family.");
  }
  return lines;
}

// ── Test runner ───────────────────────────────────────────────────────────────

let passed = 0;
let failed = 0;

function test(name, fn) {
  try {
    fn();
    console.log(`  ✓  ${name}`);
    passed++;
  } catch (err) {
    console.error(`  ✗  ${name}`);
    console.error(`     ${err.message}`);
    failed++;
  }
}

// ── isSameModelFamily: top-level family detection ────────────────────────────

console.log("\nisSameModelFamily — top-level family detection");

test("claude-sonnet and claude-opus are the same family", () => {
  assert.equal(isSameModelFamily("claude-sonnet-4.6", "claude-opus-4.5"), true);
});

test("claude-haiku and claude-sonnet are the same family", () => {
  assert.equal(isSameModelFamily("claude-haiku-4.5", "claude-sonnet-4.6"), true);
});

test("claude-haiku and claude-opus are the same family", () => {
  assert.equal(isSameModelFamily("claude-haiku-4.5", "claude-opus-4.6"), true);
});

test("gpt-5.2 and gpt-5.1-codex-max are the same family", () => {
  assert.equal(isSameModelFamily("gpt-5.2", "gpt-5.1-codex-max"), true);
});

test("gpt-5.3-codex and gpt-5.4 are the same family", () => {
  assert.equal(isSameModelFamily("gpt-5.3-codex", "gpt-5.4"), true);
});

test("gpt-4.1 and gpt-5.2 are the same family", () => {
  assert.equal(isSameModelFamily("gpt-4.1", "gpt-5.2"), true);
});

test("claude-sonnet and gpt-5 are different families", () => {
  assert.equal(isSameModelFamily("claude-sonnet-4.6", "gpt-5"), false);
});

test("claude-opus and gpt-5.1-codex-max are different families", () => {
  assert.equal(isSameModelFamily("claude-opus-4.5", "gpt-5.1-codex-max"), false);
});

test("null/undefined inputs return false", () => {
  assert.equal(isSameModelFamily(null, "gpt-5"), false);
  assert.equal(isSameModelFamily("claude-sonnet-4.6", undefined), false);
  assert.equal(isSameModelFamily(null, null), false);
});

// ── Review ordering: cross-family candidates come first ───────────────────────

console.log("\norderForReview — cross-family candidates ranked first");

test("after Claude-Sonnet impl, GPT models rank before Claude-Opus in review", () => {
  const candidates = [
    { id: "gpt-5" },
    { id: "gpt-5.4" },
    { id: "claude-opus-4.5" },
    { id: "claude-opus-4.6" },
    { id: "gpt-5.1-codex-max" },
  ];
  const ordered = orderForReview(candidates, "claude-sonnet-4.6");
  const gpt5Idx = ordered.findIndex((c) => c.id === "gpt-5");
  const opusIdx = ordered.findIndex((c) => c.id === "claude-opus-4.5");
  assert.ok(gpt5Idx < opusIdx, `gpt-5 (idx ${gpt5Idx}) should precede claude-opus-4.5 (idx ${opusIdx})`);
});

test("after Claude-Opus impl, Claude-Sonnet does not rank ahead of GPT", () => {
  const candidates = [
    { id: "gpt-5" },
    { id: "gpt-5.4" },
    { id: "claude-sonnet-4.6" },
    { id: "claude-sonnet-4" },
  ];
  const ordered = orderForReview(candidates, "claude-opus-4.5");
  const gpt5Idx = ordered.findIndex((c) => c.id === "gpt-5");
  const sonnetIdx = ordered.findIndex((c) => c.id === "claude-sonnet-4.6");
  // Both are in the claude family → same-family penalty (score 1) for Claude-Sonnet;
  // GPT should come first (score 0).
  assert.ok(gpt5Idx < sonnetIdx, `gpt-5 (idx ${gpt5Idx}) should precede claude-sonnet-4.6 (idx ${sonnetIdx})`);
});

test("after GPT-5.2 impl, all Claude models rank before other GPT models", () => {
  const candidates = [
    { id: "gpt-5" },
    { id: "gpt-5.4" },
    { id: "claude-sonnet-4.6" },
    { id: "claude-opus-4.5" },
    { id: "gpt-5.1-codex-max" },
  ];
  const ordered = orderForReview(candidates, "gpt-5.2");
  const claudeSonnetIdx = ordered.findIndex((c) => c.id === "claude-sonnet-4.6");
  const claudeOpusIdx = ordered.findIndex((c) => c.id === "claude-opus-4.5");
  const gpt5Idx = ordered.findIndex((c) => c.id === "gpt-5");
  const codexIdx = ordered.findIndex((c) => c.id === "gpt-5.1-codex-max");
  assert.ok(claudeSonnetIdx < gpt5Idx, `claude-sonnet-4.6 should precede gpt-5`);
  assert.ok(claudeOpusIdx < gpt5Idx, `claude-opus-4.5 should precede gpt-5`);
  // codex is also GPT family — should be penalised alongside other GPT models
  assert.ok(claudeSonnetIdx < codexIdx, `claude-sonnet-4.6 should precede gpt-5.1-codex-max`);
});

test("exact implementation model is ranked last", () => {
  const candidates = [
    { id: "claude-sonnet-4.6" },
    { id: "gpt-5" },
    { id: "claude-opus-4.5" },
  ];
  const ordered = orderForReview(candidates, "claude-sonnet-4.6");
  assert.equal(ordered[ordered.length - 1].id, "claude-sonnet-4.6");
});

test("no last implementation model → order unchanged", () => {
  const candidates = [{ id: "gpt-5" }, { id: "claude-sonnet-4.6" }];
  const ordered = orderForReview(candidates, null);
  assert.deepEqual(ordered, candidates);
});

// ── buildAdditionalContext: fallback messages ─────────────────────────────────

console.log("\nreviewDiversityLines — fallback messages");

test("no fallback note when a cross-family model was selected", () => {
  const lines = reviewDiversityLines("gpt-5", "claude-sonnet-4.6");
  assert.equal(lines.length, 1);
  assert.ok(lines[0].includes("claude-sonnet-4.6"), "diversity note should name the impl model");
});

test("exact-reuse note when selected === lastImpl", () => {
  const lines = reviewDiversityLines("claude-sonnet-4.6", "claude-sonnet-4.6");
  assert.equal(lines.length, 2);
  assert.ok(lines[1].includes("fell back"), `expected 'fell back' note, got: ${lines[1]}`);
});

test("same-family note when same-family-but-different model was selected", () => {
  // claude-opus-4.5 is same family as claude-sonnet-4.6; should surface the same-family note
  const lines = reviewDiversityLines("claude-opus-4.5", "claude-sonnet-4.6");
  assert.equal(lines.length, 2);
  assert.ok(lines[1].includes("same family"), `expected 'same family' note, got: ${lines[1]}`);
});

test("same-family note for GPT-codex fallback after GPT impl", () => {
  const lines = reviewDiversityLines("gpt-5.1-codex-max", "gpt-5.2");
  assert.equal(lines.length, 2);
  assert.ok(lines[1].includes("same family"), `expected 'same family' note, got: ${lines[1]}`);
});

test("no lines when lastImplementationModel is null", () => {
  const lines = reviewDiversityLines("gpt-5", null);
  assert.equal(lines.length, 0);
});

// ── Results ───────────────────────────────────────────────────────────────────

console.log(`\n${passed} passed, ${failed} failed\n`);
process.exitCode = failed > 0 ? 1 : 0;
